// La comparaison colonne-à-colonne (qty_stock <= qty_min_threshold) n'est pas
// supportée nativement par PostgREST — on effectue le filtrage ici.
const response = $input.first().json;
const allParts = Array.isArray(response) ? response : [response];

const lowStockItems = allParts.filter(
  p => typeof p.qty_stock === 'number' &&
       typeof p.qty_min_threshold === 'number' &&
       p.qty_stock <= p.qty_min_threshold
);

return [{
  json: {
    lowStockItems,
    count:         lowStockItems.length,
    rupture_count: lowStockItems.filter(p => p.qty_stock === 0).length,
    bas_count:     lowStockItems.filter(p => p.qty_stock > 0).length,
    hasLowStock:   lowStockItems.length > 0
  }
}];

const { lowStockItems, rupture_count, bas_count } = $input.first().json;

const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const subject = `⚠️ Stock bas — ${lowStockItems.length} pièce(s) à commander — ${today}`;
const summary = `${rupture_count} pièce(s) en rupture, ${bas_count} pièce(s) en stock bas`;

// Génération des lignes du tableau HTML
const rows = lowStockItems.map(p => {
  const isRupture = p.qty_stock === 0;
  const rowBg     = isRupture ? '#fef2f2' : '#fffbeb';
  const qtyColor  = isRupture ? '#dc2626' : '#d97706';
  const badge     = isRupture
    ? '<span style="background:#dc2626;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:bold;">RUPTURE</span>'
    : '<span style="background:#d97706;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:bold;">BAS</span>';
  const supplierCell = p.supplier_name
    ? (p.supplier_url
        ? `<a href="${p.supplier_url}" style="color:#2563eb;">${p.supplier_name}</a>`
        : p.supplier_name)
    : '—';
  return `
    <tr style="background:${rowBg};">
      <td style="padding:10px 12px;border:1px solid #e5e7eb;font-weight:500;">${p.part_name}</td>
      <td style="padding:10px 12px;border:1px solid #e5e7eb;font-family:monospace;">${p.sku ?? '—'}</td>
      <td style="padding:10px 12px;border:1px solid #e5e7eb;font-weight:bold;color:${qtyColor};text-align:center;">${p.qty_stock}</td>
      <td style="padding:10px 12px;border:1px solid #e5e7eb;text-align:center;">${p.qty_min_threshold}</td>
      <td style="padding:10px 12px;border:1px solid #e5e7eb;text-align:center;">${badge}</td>
      <td style="padding:10px 12px;border:1px solid #e5e7eb;">${supplierCell}</td>
    </tr>`;
}).join('');

const htmlContent = `<!DOCTYPE html>
<html lang="fr">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:Arial,sans-serif;color:#1f2937;max-width:820px;margin:0 auto;padding:24px;">

  <div style="border-left:4px solid #dc2626;padding:0 16px;margin-bottom:24px;">
    <h2 style="margin:12px 0 4px;color:#dc2626;">⚠️ Alerte stock RepairFlow</h2>
    <p style="margin:0;color:#6b7280;font-size:14px;">${today}</p>
  </div>

  <div style="background:#fef3c7;border:1px solid #f59e0b;border-radius:8px;padding:14px 18px;margin-bottom:24px;">
    <strong style="color:#92400e;">${summary}</strong>
  </div>

  <table style="width:100%;border-collapse:collapse;font-size:14px;">
    <thead>
      <tr style="background:#1f2937;color:#fff;">
        <th style="padding:12px;text-align:left;border:1px solid #374151;">Pièce</th>
        <th style="padding:12px;text-align:left;border:1px solid #374151;">SKU</th>
        <th style="padding:12px;text-align:center;border:1px solid #374151;">Stock actuel</th>
        <th style="padding:12px;text-align:center;border:1px solid #374151;">Seuil min.</th>
        <th style="padding:12px;text-align:center;border:1px solid #374151;">Statut</th>
        <th style="padding:12px;text-align:left;border:1px solid #374151;">Fournisseur</th>
      </tr>
    </thead>
    <tbody>
      ${rows}
    </tbody>
  </table>

  <div style="margin-top:28px;">
    <a href="${$env.APP_URL}/admin/inventory"
       style="background:#2563eb;color:#fff;padding:12px 24px;border-radius:6px;text-decoration:none;font-weight:bold;display:inline-block;">
      Gérer le stock →
    </a>
  </div>

  <hr style="margin:32px 0;border:none;border-top:1px solid #e5e7eb;">
  <p style="color:#9ca3af;font-size:12px;margin:0;">
    Email généré automatiquement par RepairFlow · ${new Date().toISOString()}
  </p>

</body>
</html>`;

return [{
  json: {
    email_subject:  subject,
    email_html:     htmlContent,
    summary,
    items_count:    lowStockItems.length,
    rupture_count,
    bas_count
  }
}];

const emailData = $('Build Stock Email HTML').first().json;

const logEntry = {
  workflow:      'stock-alert-daily-check',
  date:          new Date().toISOString(),
  items_count:   emailData.items_count,
  rupture_count: emailData.rupture_count,
  bas_count:     emailData.bas_count,
  summary:       emailData.summary,
  email_sent:    true,
  recipient:     $env.SHOP_EMAIL
};

// Trace dans les logs n8n (visible dans l'exécution)
console.log('[RepairFlow][StockAlert]', JSON.stringify(logEntry));

return [{ json: logEntry }];
